<?php
 namespace WPAICG\Chat\Core\AIService\GenerateResponse; if (!defined('ABSPATH')) { exit; } function build_final_system_instruction_logic( array $bot_settings, int $post_id, string $base_instructions, string $all_formatted_results_for_instruction ): string { $instruction_context = [ 'base_instructions' => $base_instructions, 'bot_settings' => $bot_settings, 'post_id' => $post_id ]; if (!empty($all_formatted_results_for_instruction)) { $instruction_context['vector_search_results'] = trim($all_formatted_results_for_instruction); } return \WPAICG\Core\AIPKit_Instruction_Manager::build_instructions($instruction_context); }